<div class="pair"><dt><svg aria-hidden="true" class="pg-icon is-16"><use href="#pg-eat"></use></svg> Order</dt><dd>Hoi tod oyster omelette</dd></div>
<div class="pair"><dt><svg aria-hidden="true" class="pg-icon is-16"><use href="#pg-cash"></use></svg> Payment</dt><dd>Cash only</dd></div>
</dl>
<div class="pros-cons">
